const { DynamoDBClient } = require('@aws-sdk/client-dynamodb');
const { DynamoDBDocumentClient, UpdateCommand } = require('@aws-sdk/lib-dynamodb');
const { SecretsManagerClient, GetSecretValueCommand } = require('@aws-sdk/client-secrets-manager');
const https = require('https');

const dynamoClient = new DynamoDBClient({});
const docClient = DynamoDBDocumentClient.from(dynamoClient);
const secretsClient = new SecretsManagerClient({});

const ORDERS_TABLE = process.env.ORDERS_TABLE;
const PAYMENT_API_SECRET_ARN = process.env.PAYMENT_API_SECRET_ARN;
const ALLOWED_PAYMENT_METHODS = ['credit_card', 'debit_card', 'bank_transfer'];
const MAX_AMOUNT = 1000000;
const MIN_AMOUNT = 1;

let cachedApiKey = null;
let cacheExpiry = 0;

async function getPaymentApiKey() {
  const now = Date.now();
  if (cachedApiKey && now < cacheExpiry) {
    return cachedApiKey;
  }

  const command = new GetSecretValueCommand({
    SecretId: PAYMENT_API_SECRET_ARN
  });
  
  const response = await secretsClient.send(command);
  const secret = JSON.parse(response.SecretString);
  
  cachedApiKey = secret.apiKey;
  cacheExpiry = now + 3600000;
  
  return cachedApiKey;
}

function validateOrder(order) {
  if (!order || typeof order !== 'object') {
    throw new Error('Invalid order format');
  }

  const orderId = String(order.orderId || '').trim();
  if (!orderId || orderId.length > 100 || !/^[a-zA-Z0-9-_]+$/.test(orderId)) {
    throw new Error('Invalid orderId');
  }

  const amount = parseFloat(order.amount);
  if (isNaN(amount) || amount < MIN_AMOUNT || amount > MAX_AMOUNT) {
    throw new Error('Invalid amount');
  }

  const currency = String(order.currency || '').trim().toUpperCase();
  if (!/^[A-Z]{3}$/.test(currency)) {
    throw new Error('Invalid currency');
  }

  const paymentMethod = String(order.paymentMethod || '').trim().toLowerCase();
  if (!ALLOWED_PAYMENT_METHODS.includes(paymentMethod)) {
    throw new Error('Invalid payment method');
  }

  const customerId = String(order.customerId || '').trim();
  if (!customerId || customerId.length > 100 || !/^[a-zA-Z0-9-_]+$/.test(customerId)) {
    throw new Error('Invalid customerId');
  }

  return {
    orderId,
    amount,
    currency,
    paymentMethod,
    customerId
  };
}

function callPaymentApi(validatedOrder, apiKey) {
  return new Promise((resolve, reject) => {
    const payload = JSON.stringify({
      orderId: validatedOrder.orderId,
      amount: validatedOrder.amount,
      currency: validatedOrder.currency,
      paymentMethod: validatedOrder.paymentMethod,
      customerId: validatedOrder.customerId
    });

    const options = {
      hostname: 'api.payment-provider.com',
      port: 443,
      path: '/v1/payments',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(payload),
        'Authorization': `Bearer ${apiKey}`,
        'X-Request-ID': validatedOrder.orderId
      },
      timeout: 10000
    };

    const req = https.request(options, (res) => {
      let data = '';

      res.on('data', (chunk) => {
        data += chunk;
        if (data.length > 1048576) {
          req.destroy();
          reject(new Error('Response too large'));
        }
      });

      res.on('end', () => {
        if (res.statusCode >= 200 && res.statusCode < 300) {
          try {
            const response = JSON.parse(data);
            resolve(response);
          } catch (e) {
            reject(new Error('Invalid JSON response'));
          }
        } else {
          reject(new Error(`Payment API error: ${res.statusCode}`));
        }
      });
    });

    req.on('error', (e) => {
      reject(e);
    });

    req.on('timeout', () => {
      req.destroy();
      reject(new Error('Request timeout'));
    });

    req.write(payload);
    req.end();
  });
}

async function updateOrderStatus(orderId, status, transactionId) {
  const sanitizedStatus = String(status).trim();
  if (!/^[a-z_]+$/.test(sanitizedStatus)) {
    throw new Error('Invalid status format');
  }

  const updateParams = {
    TableName: ORDERS_TABLE,
    Key: { orderId },
    UpdateExpression: 'SET #status = :status, updatedAt = :updatedAt',
    ExpressionAttributeNames: {
      '#status': 'status'
    },
    ExpressionAttributeValues: {
      ':status': sanitizedStatus,
      ':updatedAt': new Date().toISOString()
    }
  };

  if (transactionId) {
    const sanitizedTxId = String(transactionId).trim();
    if (sanitizedTxId.length > 100) {
      throw new Error('Transaction ID too long');
    }
    updateParams.UpdateExpression += ', transactionId = :transactionId';
    updateParams.ExpressionAttributeValues[':transactionId'] = sanitizedTxId;
  }

  await docClient.send(new UpdateCommand(updateParams));
}

async function processOrder(order) {
  let validatedOrder;
  
  try {
    validatedOrder = validateOrder(order);
  } catch (error) {
    console.error('Validation failed:', { error: error.message });
    return;
  }

  try {
    const apiKey = await getPaymentApiKey();
    const paymentResponse = await callPaymentApi(validatedOrder, apiKey);
    
    await updateOrderStatus(
      validatedOrder.orderId,
      'completed',
      paymentResponse.transactionId
    );
    
    console.log('Order processed successfully:', { orderId: validatedOrder.orderId });
  } catch (error) {
    console.error('Processing failed:', { 
      orderId: validatedOrder.orderId,
      error: error.message 
    });
    
    try {
      await updateOrderStatus(validatedOrder.orderId, 'failed');
    } catch (updateError) {
      console.error('Status update failed:', { 
        orderId: validatedOrder.orderId,
        error: updateError.message 
      });
    }
  }
}

exports.handler = async (event) => {
  const promises = event.Records.map(async (record) => {
    try {
      const order = JSON.parse(record.body);
      await processOrder(order);
    } catch (error) {
      console.error('Record processing failed:', { error: error.message });
    }
  });

  await Promise.all(promises);
  
  return { statusCode: 200 };
};